const AWS = require('aws-sdk');

AWS.config.update({
  region: process.env.AWS_REGION || 'us-east-1'
});

if (process.env.AWS_ACCESS_KEY_ID && process.env.AWS_SECRET_ACCESS_KEY) {
  AWS.config.update({
    accessKeyId: process.env.AWS_ACCESS_KEY_ID,
    secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY
  });
}

const options = {
  region: process.env.AWS_REGION || 'us-east-1'
};

const docClient = new AWS.DynamoDB.DocumentClient(options);

const tables = {
  TODO_TABLE: process.env.TODO_TABLE_NAME || 'todo-monolith-table',
  USER_TABLE: process.env.USER_TABLE_NAME || 'todo-monolith-users'
};

module.exports = {
  docClient,
  tables
};

function authenticateToken(req, res, next) {

  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.startsWith('Bearer ')
    ? authHeader.substring(7)
    : authHeader;

  if (!token) {
    return res.status(401).json({
      message: 'No authentication token provided. Please log in first.'
    });
  }

  const decoded = verifyToken(token);

  if (!decoded) {
    return res.status(401).json({
      message: 'The authentication token is invalid or has expired. Please log in again.'
    });
  }

  req.user = {
    username: decoded.username
  };

  next();
}

router.post('/register', async (req, res) => {
  try {
    const { username, password, email } = req.body;

    if (!username || !password) {
      return res.status(400).json({
        message: 'Username and password cannot be empty'
      });
    }

    if (password.length < 6) {
      return res.status(400).json({
        message: 'Password must be at least 6 characters long'
      });
    }

    const checkParams = {
      TableName: tables.USER_TABLE,
      Key: { username }
    };

    const existingUser = await docClient.get(checkParams).promise();

    if (existingUser.Item) {
      return res.status(400).json({
        message: 'Username already exists, please choose another username'
      });
    }

    const hashedPassword = await bcrypt.hash(password, 10);

    const user = {
      username,
      password: hashedPassword,
      email: email || '',
      createdAt: new Date().toISOString()
    };

    const putParams = {
      TableName: tables.USER_TABLE,
      Item: user
    };

    await docClient.put(putParams).promise();

    const token = generateToken(username);

    res.status(201).json({
      message: 'Registration successful',
      token,
      username
    });

  } catch (error) {
    console.error('Registration failed:', error);
    res.status(500).json({
      message: 'Registration failed, please try again later',
      error: error.message
    });
  }
});

router.post('/login', async (req, res) => {
  try {
    const { username, password } = req.body;

    if (!username || !password) {
      return res.status(400).json({
        message: 'Username and password cannot be empty'
      });
    }

    const params = {
      TableName: tables.USER_TABLE,
      Key: { username }
    };

    const result = await docClient.get(params).promise();
    const user = result.Item;

    if (!user) {
      return res.status(401).json({
        message: 'Invalid username or password'
      });
    }

    const isPasswordValid = await bcrypt.compare(password, user.password);

    if (!isPasswordValid) {
      return res.status(401).json({
        message: 'Invalid username or password'
      });
    }

    const token = generateToken(username);

    res.json({
      message: 'Login successful',
      token,
      username
    });

  } catch (error) {
    console.error('Login failed:', error);
    res.status(500).json({
      message: 'Login failed, please try again later',
      error: error.message
    });
  }
});

router.get('/item', async (req, res) => {
  try {
    const username = req.user.username;

    const params = {
      TableName: tables.TODO_TABLE,
      KeyConditionExpression: "#username = :username",
      ExpressionAttributeNames: {
        "#username": "cognito-username"
      },
      ExpressionAttributeValues: {
        ":username": username
      }
    };

    const result = await docClient.query(params).promise();

    res.json({
      Items: result.Items || [],
      Count: result.Count || 0
    });

  } catch (error) {
    console.error('Failed to fetch todo list:', error);
    res.status(400).json({
      message: error.message
    });
  }
});

router.get('/item/:id', async (req, res) => {
  try {
    const username = req.user.username;
    const { id } = req.params;

    if (!id || !/^[\w-]+$/.test(id)) {
      return res.status(400).json({
        message: 'Invalid request: Invalid todo item ID'
      });
    }

    const params = {
      TableName: tables.TODO_TABLE,
      Key: {
        "cognito-username": username,
        id: id
      }
    };

    const result = await docClient.get(params).promise();

    if (!result.Item) {
      return res.status(404).json({
        message: 'Todo item not found'
      });
    }

    res.json(result);

  } catch (error) {
    console.error('Failed to fetch todo item:', error);
    res.status(400).json({
      message: error.message
    });
  }
});

router.post('/item', async (req, res) => {
  try {
    const username = req.user.username;
    const { item, completed } = req.body;

    if (!item) {
      return res.status(400).json({
        message: 'Invalid request: Todo item content cannot be empty'
      });
    }
    const now = new Date().toISOString();
    const todoItem = {
      "cognito-username": username,
      id: uuidv1(),
      item: item,
      completed: completed || false,
      creation_date: now,
      lastupdate_date: now
    };

    const params = {
      TableName: tables.TODO_TABLE,
      Item: todoItem
    };

    await docClient.put(params).promise();

    res.json({
      message: 'Todo item created successfully',
      item: todoItem
    });

  } catch (error) {
    console.error('Failed to create todo item:', error);
    res.status(400).json({
      message: error.message
    });
  }
});

router.put('/item/:id', async (req, res) => {
  try {
    const username = req.user.username;
    const { id } = req.params;
    const { item, completed } = req.body;

    if (!id || !/^[\w-]+$/.test(id)) {
      return res.status(400).json({
        message: 'Invalid request: Invalid todo item ID'
      });
    }

    if (item === undefined || completed === undefined) {
      return res.status(400).json({
        message: 'Invalid request: Missing required fields'
      });
    }
    const params = {
      TableName: tables.TODO_TABLE,
      Key: {
        "cognito-username": username,
        id: id
      },
      UpdateExpression: "set completed = :c, lastupdate_date = :lud, #i = :i",
      ExpressionAttributeNames: {
        "#i": "item"
      },
      ExpressionAttributeValues: {
        ":c": completed,
        ":lud": new Date().toISOString(),
        ":i": item
      },
      ReturnValues: "ALL_NEW"
    };

    const result = await docClient.update(params).promise();

    res.json({
      message: 'Todo item updated successfully',
      Attributes: result.Attributes
    });

  } catch (error) {
    console.error('Failed to update todo item:', error);
    res.status(400).json({
      message: error.message
    });
  }
});

router.post('/item/:id/done', async (req, res) => {
  try {
    const username = req.user.username;
    const { id } = req.params;

    if (!id || !/^[\w-]+$/.test(id)) {
      return res.status(400).json({
        message: 'Invalid request: Invalid todo item ID'
      });
    }
    const params = {
      TableName: tables.TODO_TABLE,
      Key: {
        "cognito-username": username,
        id: id
      },
      UpdateExpression: "set #field = :value",
      ExpressionAttributeNames: {
        "#field": "completed"
      },
      ExpressionAttributeValues: {
        ":value": true
      },
      ReturnValues: "ALL_NEW"
    };

    const result = await docClient.update(params).promise();

    res.json({
      message: 'Todo item marked as completed',
      Attributes: result.Attributes
    });

  } catch (error) {
    console.error('Failed to mark todo item as completed:', error);
    res.status(400).json({
      message: error.message
    });
  }
});

router.delete('/item/:id', async (req, res) => {
  try {
    const username = req.user.username;
    const { id } = req.params;

    if (!id || !/^[\w-]+$/.test(id)) {
      return res.status(400).json({
        message: 'Invalid request: Invalid todo item ID'
      });
    }
    const params = {
      TableName: tables.TODO_TABLE,
      Key: {
        "cognito-username": username,
        id: id
      }
    };

    await docClient.delete(params).promise();

    res.json({
      message: 'Todo item deleted successfully'
    });

  } catch (error) {
    console.error('Failed to delete todo item:', error);
    res.status(400).json({
      message: error.message
    });
  }
});

async function tableExists(tableName) {
  try {
    await dynamodb.describeTable({ TableName: tableName }).promise();
    return true;
  } catch (error) {
    if (error.code === 'ResourceNotFoundException') {
      return false;
    }
    throw error;
  }
}

async function waitForTable(tableName) {
  console.log(`  Waiting for table ${tableName} to become ACTIVE...`);
  let attempts = 0;
  const maxAttempts = 30;

  while (attempts < maxAttempts) {
    try {
      const result = await dynamodb.describeTable({ TableName: tableName }).promise();
      const status = result.Table.TableStatus;

      if (status === 'ACTIVE') {
        console.log(`  ✓ Table ${tableName} is ready`);
        return true;
      }

      process.stdout.write('.');
      await new Promise(resolve => setTimeout(resolve, 2000));
      attempts++;
    } catch (error) {
      console.error(`\n  ✗ Error checking table status: ${error.message}`);
      return false;
    }
  }

  console.log(`\n  ✗ Timeout waiting for table`);
  return false;
}

async function createTodoTable() {
  const params = {
    TableName: TODO_TABLE,
    KeySchema: [
      { AttributeName: 'cognito-username', KeyType: 'HASH' },
      { AttributeName: 'id', KeyType: 'RANGE' }
    ],
    AttributeDefinitions: [
      { AttributeName: 'cognito-username', AttributeType: 'S' },
      { AttributeName: 'id', AttributeType: 'S' }
    ],
    BillingMode: 'PAY_PER_REQUEST',
    Tags: [
      { Key: 'Application', Value: 'TodoMonolith' },
      { Key: 'Environment', Value: process.env.NODE_ENV || 'development' }
    ]
  };

  try {
    if (await tableExists(TODO_TABLE)) {
      console.log(`- Table ${TODO_TABLE} already exists, skipping creation`);
      return false;
    }

    await dynamodb.createTable(params).promise();
    console.log(`✓ Table ${TODO_TABLE} created successfully`);
    console.log(`  Partition key: cognito-username (String)`);
    console.log(`  Sort key: id (String)`);
    return true;
  } catch (error) {
    if (error.code === 'ResourceInUseException') {
      console.log(`- Table ${TODO_TABLE} already exists`);
      return false;
    }
    throw error;
  }
}

async function createUserTable() {
  const params = {
    TableName: USER_TABLE,
    KeySchema: [
      { AttributeName: 'username', KeyType: 'HASH' }
    ],
    AttributeDefinitions: [
      { AttributeName: 'username', AttributeType: 'S' }
    ],
    BillingMode: 'PAY_PER_REQUEST',
    Tags: [
      { Key: 'Application', Value: 'TodoMonolith' },
      { Key: 'Environment', Value: process.env.NODE_ENV || 'development' }
    ]
  };

  try {
    if (await tableExists(USER_TABLE)) {
      console.log(`- Table ${USER_TABLE} already exists, skipping creation`);
      return false;
    }

    await dynamodb.createTable(params).promise();
    console.log(`✓ Table ${USER_TABLE} created successfully`);
    console.log(`  Primary key: username (String)`);
    return true;
  } catch (error) {
    if (error.code === 'ResourceInUseException') {
      console.log(`- Table ${USER_TABLE} already exists`);
      return false;
    }
    throw error;
  }
}

